phase1.code:
using UnityEngine;

// ScriptableObject — data container that persists outside scenes
[CreateAssetMenu(fileName = "NewItem", menuName = "Game/Item")]
public class ItemData : ScriptableObject
{
    public string itemName;
    public string description;
    public int value;
    public int weight;
    public Sprite icon;
    public ItemType itemType;
}

public enum ItemType
{
    Weapon,
    Armor,
    Potion,
    Quest,
    Key
}

// Another ScriptableObject for enemies
[CreateAssetMenu(fileName = "NewEnemy", menuName = "Game/Enemy")]
public class EnemyData : ScriptableObject
{
    public string enemyName;
    public int health;
    public int attackPower;
    public int defense;
    public int experienceValue;
    public Sprite sprite;
    public float moveSpeed;

    public void DisplayStats()
    {
        Debug.Log("=== Enemy: " + enemyName + " ===");
        Debug.Log("Health: " + health);
        Debug.Log("Attack: " + attackPower);
        Debug.Log("Defense: " + defense);
        Debug.Log("XP Value: " + experienceValue);
    }
}

// MonoBehaviour that uses ScriptableObjects
public class ScriptableObjectExample : MonoBehaviour
{
    public ItemData sword;
    public ItemData healthPotion;
    public EnemyData goblin;
    public EnemyData boss;

    void Start()
    {
        // Display item data
        Debug.Log("=== Items ===");
        Debug.Log("Sword: " + sword.itemName + " (Value: " + sword.value + ")");
        Debug.Log("Potion: " + healthPotion.itemName + " (Type: " + healthPotion.itemType + ")");

        // Display enemy data
        goblin.DisplayStats();
        boss.DisplayStats();

        // Create a new item at runtime (for saving, etc.)
        ItemData newItem = ScriptableObject.CreateInstance<ItemData>();
        newItem.itemName = "Mystic Orb";
        newItem.value = 100;
        newItem.itemType = ItemType.Quest;

        Debug.Log("Created: " + newItem.itemName + " (Type: " + newItem.itemType + ")");
    }
}

