using UnityEngine;

public class ItemData : MonoBehaviour  // Wrong base class!
{
    public string itemName;
    public int value;
}

public class ScriptableError : MonoBehaviour
{
    public ItemData sword;  // This is a MonoBehaviour, not a ScriptableObject

    void Start()
    {
        // This will cause errors because ItemData is a MonoBehaviour, not a ScriptableObject
        Debug.Log(sword.itemName);
    }
}

phase2.explanation:
You inherited from `MonoBehaviour` instead of `ScriptableObject`.

**The fix:**
```csharp
public class ItemData : ScriptableObject  // ← Correct base class
{
    public string itemName;
    public int value;
}
```

**Sharp-chan says:**
"ScriptableObjects inherit from `ScriptableObject`, not `MonoBehaviour`. They're data containers, not game objects."
